INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -416.5, 62, 1, 1, "カリン", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 0.0, "2025/01/31 12:00:00", "2030/01/01 14:59:59", 2, 1000001, 3.414, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -416.5, 62, 1, 2, "カリン", "ミッションをクリアして、\n報酬をゲットしましょう！", 0.0, "2025/01/31 12:00:00", "2030/01/01 14:59:59", 2, 1000002, 3.099, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -416.5, 63, 1, 3, "カリン", "受け取ることができる\n報酬があるようです\n確認してみてください", 0.0, "2025/01/31 12:00:00", "2030/01/01 14:59:59", 2, 1000003, 2.801, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -416.5, 63, 1, 4, "カリン", "報酬がもらえますよ！\nチェックしてみてください", 0.0, "2025/01/31 12:00:00", "2030/01/01 14:59:59", 2, 1000004, 0.0, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -363.0, 64, 1, 5, "カリン", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 0.0, "2025/01/31 12:00:00", "2030/01/01 14:59:59", 1, 1000005, 2.12, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -363.0, 64, 1, 6, "カリン", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 0.0, "2025/01/31 12:00:00", "2030/01/01 14:59:59", 2, 1000006, 1.68, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -363.0, 64, 1, 7, "カリン", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 0.0, "2025/01/31 12:00:00", "2030/01/01 14:59:59", 1, 1000007, 2.33, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (133701, -285.0, 61, 10201, 101, "ラビリスタ", "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", -6.0, "2025/01/31 12:00:00", "2030/01/01 14:59:59", 7, 1020101, 5.18, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (133901, -285.0, 61, 10201, 201, "クリスティーナ", "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", -2.0, "2025/01/31 12:00:00", "2030/01/01 14:59:59", 2, 1020102, 8.77, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (133801, -285.0, 61, 10201, 301, "ネネカ", "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 0.0, "2025/01/31 12:00:00", "2030/01/01 14:59:59", 1, 1020103, 15.5, 6);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (134301, -285.0, 61, 10202, 101, "ランファ", "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 0.0, "2025/02/28 12:00:00", "2030/01/01 14:59:59", 5, 1020201, 9.061, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (134401, -285.0, 61, 10202, 201, "チカ", "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 0.0, "2025/02/28 12:00:00", "2030/01/01 14:59:59", 2, 1020202, 7.699, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (134601, -285.0, 61, 10203, 101, "アオイ", "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 0.0, "2025/03/31 12:00:00", "2030/01/01 14:59:59", 2, 1020301, 8.595, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (134501, -285.0, 61, 10203, 201, "クローチェ", "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 0.0, "2025/03/31 12:00:00", "2030/01/01 14:59:59", 2, 1020302, 7.758, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (132302, -285.0, 61, 10204, 101, "ルイズマリー", "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 0.0, "2025/04/30 12:00:00", "2030/01/01 14:59:59", 6, 1020401, 7.0, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (132402, -285.0, 61, 10204, 201, "イロハ", "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 0.0, "2025/04/30 12:00:00", "2030/01/01 14:59:59", 2, 1020402, 7.904, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (132502, -285.0, 61, 10204, 301, "ソノ", "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 0.0, "2025/04/30 12:00:00", "2030/01/01 14:59:59", 2, 1020403, 8.487, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (134901, -285.0, 61, 10205, 101, "カノン", "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 0.0, "2025/05/31 12:00:00", "2030/01/01 14:59:59", 2, 1020502, 8.763, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (134801, -285.0, 61, 10205, 201, "ツムギ", "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 0.0, "2025/05/31 12:00:00", "2030/01/01 14:59:59", 3, 1020503, 6.417, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135001, -285.0, 61, 10206, 101, "エリス", "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 0.0, "2025/06/30 12:00:00", "2030/01/01 14:59:59", 7, 1020601, 10.335, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135101, -285.0, 61, 10206, 201, "シェフィ", "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 0.0, "2025/06/30 12:00:00", "2030/01/01 14:59:59", 4, 1020602, 6.281, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135201, -285.0, 61, 10206, 301, "プレシア", "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 0.0, "2025/06/30 12:00:00", "2030/01/01 14:59:59", 2, 1020603, 12.244, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135301, -285.0, 61, 10207, 101, "クリア", "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 0.0, "2025/07/31 12:00:00", "2030/01/01 14:59:59", 8, 1020701, 6.339, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135401, -285.0, 61, 10207, 201, "アネモネ", "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 0.0, "2025/07/31 12:00:00", "2030/01/01 14:59:59", 9, 1020702, 8.184, 7);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (129101, -285.0, 61, 10208, 101, "アイラ", "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 0.0, "2025/08/31 12:00:00", "2030/01/01 14:59:59", 2, 1020801, 3.906, 9);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (129201, -285.0, 61, 10208, 201, "シナツ", "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 0.0, "2025/08/31 12:00:00", "2030/01/01 14:59:59", 2, 1020802, 14.465, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (100101, -285.0, 61, 10208, 301, "ヒヨリ", "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 0.0, "2025/08/31 12:00:00", "2030/01/01 14:59:59", 3, 1020803, 8.662, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (100301, -285.0, 61, 10208, 401, "レイ", "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 0.0, "2025/08/31 12:00:00", "2030/01/01 14:59:59", 3, 1020804, 10.915, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135802, -285.0, 61, 10209, 101, "ユキノ", "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 0.0, "2025/09/30 12:00:00", "2030/01/01 14:59:59", 7, 1020901, 6.042, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135903, -285.0, 61, 10209, 201, "サツキ", "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 0.0, "2025/09/30 12:00:00", "2030/01/01 14:59:59", 1, 1020902, 9.402, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136902, -285.0, 61, 10209, 301, "ルルィ", "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 0.0, "2025/09/30 12:00:00", "2030/01/01 14:59:59", 1, 1020903, 8.16, 8);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (137401, -285.0, 61, 10210, 101, "カスミ", "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 0.0, "2025/10/31 12:00:00", "2030/01/01 14:59:59", 2, 1021001, 5.0, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136001, -285.0, 61, 10210, 201, "アラクネ", "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 0.0, "2025/10/31 12:00:00", "2030/01/01 14:59:59", 1, 1021002, 8.12, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136202, -285.0, 61, 10210, 301, "ナーナ", "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 0.0, "2025/10/31 12:00:00", "2030/01/01 14:59:59", 2, 1021003, 6.386, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136402, -285.0, 61, 10211, 101, "ユイ", "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 0.0, "2025/11/30 12:00:00", "2030/01/01 14:59:59", 4, 1021101, 7.438, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136302, -285.0, 61, 10211, 201, "ミソラ", "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 0.0, "2025/11/30 12:00:00", "2030/01/01 14:59:59", 5, 1021102, 8.35, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136501, -285.0, 61, 10212, 101, "シズル", "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 0.0, "2025/12/31 12:00:00", "2030/01/01 14:59:59", 2, 1021201, 5.0, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (137902, -285.0, 61, 10212, 201, "リノ", "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 0.0, "2025/12/31 12:00:00", "2030/01/01 14:59:59", 2, 1021202, 5.25, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (106801, -285.0, 61, 10212, 301, "ラビリスタ", "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 0.0, "2025/12/31 12:00:00", "2030/01/01 14:59:59", 2, 1021203, 7.5, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (126501, -285.0, 61, 10213, 101, "ライラエル", "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 0.0, "2026/01/31 12:00:00", "2030/01/01 14:59:59", 2, 1021301, 8.204, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (129701, -285.0, 61, 10213, 201, "ネフィ＝ネラ", "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 0.0, "2026/01/31 12:00:00", "2030/01/01 14:59:59", 2, 1021302, 7.176, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (133101, -285.0, 61, 10213, 301, "ヴァイオレット", "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 0.0, "2026/01/31 12:00:00", "2030/01/01 14:59:59", 5, 1021303, 8.602, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138101, -285.0, 61, 10213, 102, "ライラエル", "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 0.0, "2026/02/06 12:00:00", "2030/01/01 14:59:59", 3, 1021304, 10.14, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138201, -285.0, 61, 10213, 202, "ネフィ＝ネラ", "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 0.0, "2026/02/06 12:00:00", "2030/01/01 14:59:59", 7, 1021305, 10.152, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138001, -285.0, 61, 10213, 302, "ヴァイオレット", "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 0.0, "2026/02/06 12:00:00", "2030/01/01 14:59:59", 3, 1021306, 9.688, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138301, -285.0, 61, 10213, 401, "ペコリーヌ", "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 0.0, "2026/02/12 12:00:00", "2030/01/01 14:59:59", 1, 1021307, 5.928, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138702, -285.0, 61, 10214, 101, "ワカナ", "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 0.0, "2026/02/28 12:00:00", "2030/01/01 14:59:59", 2, 1021401, 9.19, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138802, -285.0, 61, 10214, 201, "シオリ", "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 0.0, "2026/02/28 12:00:00", "2030/01/01 14:59:59", 3, 1021402, 8.724, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138902, -285.0, 61, 10215, 101, "グレイス", "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 0.0, "2026/03/31 12:00:00", "2030/01/01 14:59:59", 1, 1021501, 7.758, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (139002, -285.0, 61, 10215, 201, "キョウカ", "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 0.0, "2026/03/31 12:00:00", "2030/01/01 14:59:59", 4, 1021502, 6.375, 6);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136902, -285.0, 61, 10215, 301, "ルルィ", "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 0.0, "2026/03/31 12:00:00", "2030/01/01 14:59:59", 1, 1021503, 6.173, 6);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (139202, -285.0, 61, 10216, 101, "ミホ", "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", 0.0, "2026/04/30 12:00:00", "2030/01/01 14:59:59", 2, 1021601, 4.202, 6);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (139302, -285.0, 61, 10216, 201, "マホ", "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", 0.0, "2026/04/30 12:00:00", "2030/01/01 14:59:59", 1, 1021602, 2.842, 6);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (139402, -285.0, 61, 10216, 301, "エリカ", "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", 0.0, "2026/04/30 12:00:00", "2030/01/01 14:59:59", 1, 1021603, 4.598, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (125802, -285.0, 61, 10217, 101, "リリ", "わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！", 0.0, "2026/05/31 12:00:00", "2030/01/01 14:59:59", 3, 1021701, 6.533, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (126102, -285.0, 61, 10217, 301, "プレシア", "みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。", 0.0, "2026/05/31 12:00:00", "2030/01/01 14:59:59", 3, 1021702, 5.0, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (126002, -285.0, 61, 10217, 201, "クリア", "癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！", 0.0, "2026/05/31 12:00:00", "2030/01/01 14:59:59", 4, 1021703, 5.214, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (139501, -285.0, 61, 10217, 102, "リリ", "ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！", 0.0, "2026/05/31 12:00:00", "2030/01/01 14:59:59", 3, 1021704, 8.781, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (139601, -285.0, 61, 10217, 202, "クリア", "このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？", 0.0, "2026/05/31 12:00:00", "2030/01/01 14:59:59", 1, 1021705, 6.529, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (139701, -285.0, 61, 10217, 302, "プレシア", "ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。", 0.0, "2026/05/31 12:00:00", "2030/01/01 14:59:59", 2, 1021706, 3.195, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -416.5, 62, 2, 1, "カリン", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 0.0, "2026/04/10 12:00:00", "2030/01/01 14:59:59", 2, 2000001, 3.414, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -416.5, 62, 2, 2, "カリン", "ミッションをクリアして、\n報酬をゲットしましょう！", 0.0, "2026/04/10 12:00:00", "2030/01/01 14:59:59", 2, 2000002, 3.099, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -416.5, 63, 2, 3, "カリン", "受け取ることができる\n報酬があるようです\n確認してみてください", 0.0, "2026/04/10 12:00:00", "2030/01/01 14:59:59", 2, 2000003, 2.801, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -416.5, 63, 2, 4, "カリン", "報酬がもらえますよ！\nチェックしてみてください", 0.0, "2026/04/10 12:00:00", "2030/01/01 14:59:59", 2, 2000004, 0.0, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -363.0, 64, 2, 5, "カリン", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 0.0, "2026/04/10 12:00:00", "2030/01/01 14:59:59", 1, 2000005, 2.12, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -363.0, 64, 2, 6, "カリン", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 0.0, "2026/04/10 12:00:00", "2030/01/01 14:59:59", 2, 2000006, 1.68, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, -363.0, 64, 2, 7, "カリン", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 0.0, "2026/04/10 12:00:00", "2030/01/01 14:59:59", 1, 2000007, 2.33, 2);
